// Alle Attachments der ERSTEN Mail extrahieren
const mails = $input.all();
if (mails.length === 0) return [];

mails.sort((a, b) => new Date(b.json.receivedDateTime || 0) - new Date(a.json.receivedDateTime || 0));

const mail = mails[0];
const binary = mail.binary || {};
const results = [];
let attachmentIndex = 0;
const totalAttachments = Object.keys(binary).length;
if (totalAttachments === 0) return [];

for (const [key, data] of Object.entries(binary)) {
  const filename = data.fileName || '';
  const mimeType = data.mimeType || '';
  const fileSize = data.fileSize || 0;
  const isPdf = filename.toLowerCase().endsWith('.pdf') || mimeType === 'application/pdf';

  let fileSizeFormatted = '';
  if (fileSize < 1024) fileSizeFormatted = fileSize + ' B';
  else if (fileSize < 1024 * 1024) fileSizeFormatted = (fileSize / 1024).toFixed(1) + ' KB';
  else fileSizeFormatted = (fileSize / (1024 * 1024)).toFixed(1) + ' MB';

  results.push({
    json: {
      mailId: mail.json.id,
      mailSubject: mail.json.subject || 'Kein Betreff',
      mailFrom: mail.json.from?.emailAddress?.address || 'unbekannt',
      mailDate: mail.json.receivedDateTime || 'unbekannt',
      filename, isPdf, mimeType, fileSize, fileSizeFormatted,
      binaryKey: key, attachmentIndex, totalAttachments,
      status: 'pending', error: null
    },
    binary: { data }
  });
  attachmentIndex++;
}
return results;

// PDF Passwortschutz prüfen via /Encrypt Marker
const input = $input.first();
const binaryData = input.binary?.data;

if (!binaryData || !binaryData.data) {
  return { json: { ...input.json, pdfProtected: true, pdfCheckStatus: '✗ Keine Binary-Daten vorhanden' }, binary: input.binary };
}

try {
  const raw = Buffer.from(binaryData.data, 'base64').toString('latin1');
  const isEncrypted = raw.includes('/Encrypt');
  return {
    json: { ...input.json, pdfProtected: isEncrypted, pdfCheckStatus: isEncrypted ? '✗ PDF ist passwortgeschützt' : '✓ PDF kann geöffnet werden' },
    binary: input.binary
  };
} catch(e) {
  return { json: { ...input.json, pdfProtected: true, pdfCheckStatus: '✗ PDF-Prüfung fehlgeschlagen: ' + e.message }, binary: input.binary };
}

// NAME + KATEGORIE aus Claude-Antwort parsen
const kiResult = $input.first();
let newName = null;
let category = 'Sonstiges';
try {
  if (kiResult.json.content && kiResult.json.content[0] && kiResult.json.content[0].text) {
    const responseText = kiResult.json.content[0].text.trim();
    const nameMatch = responseText.match(/NAME:\s*(.+)/i);
    const categoryMatch = responseText.match(/KATEGORIE:\s*(.+)/i);
    if (nameMatch) newName = nameMatch[1].trim();
    if (categoryMatch) category = categoryMatch[1].trim();
  }
} catch(e) {}

let prevData = null, prevBinary = null;
for (const source of ['OCR erfolgreich', 'Claude OCR verarbeiten', 'Kein PDF - durchreichen', 'PDF geschützt - durchreichen']) {
  try { const item = $(source).first(); if (item) { prevData = item.json; prevBinary = item.binary; break; } } catch(e) {}
}
if (!prevData) { prevData = $('Mehrere Anhänge nacheinander').first().json; prevBinary = $('Mehrere Anhänge nacheinander').first().binary; }

return {
  json: { ...prevData, newName, category, kiStatus: '✓ Kategorie: ' + category + (newName ? ' | Name: ' + newName : ''), status: 'ki_success' },
  binary: prevBinary
};

let prevData = null, prevBinary = null;
for (const source of ['OCR erfolgreich', 'Claude OCR verarbeiten', 'Kein PDF - durchreichen', 'PDF geschützt - durchreichen']) {
  try { const item = $(source).first(); if (item) { prevData = item.json; prevBinary = item.binary; break; } } catch(e) {}
}
if (!prevData) { prevData = $('Mehrere Anhänge nacheinander').first().json; prevBinary = $('Mehrere Anhänge nacheinander').first().binary; }

let errorMsg = 'KI-Analyse fehlgeschlagen';
try {
  const e = $input.first().json.error;
  if (e) errorMsg = typeof e === 'string' ? e : e.message || JSON.stringify(e);
} catch(e) {}

return {
  json: { ...prevData, newName: null, category: 'Sonstiges', kiStatus: '✗ KI fehlgeschlagen, nutze Originalname + Sonstiges', status: 'ki_failed', error: (prevData?.error ? prevData.error + ' | ' : '') + errorMsg },
  binary: prevBinary
};

let attachmentData = null, binaryData = null;
for (const source of ['KI erfolgreich', 'KI fehlgeschlagen (nutze Sonstiges)']) {
  try { const item = $(source).first(); if (item) { attachmentData = item.json; binaryData = item.binary; break; } } catch(e) {}
}
if (!attachmentData) throw new Error('Konnte Attachment-Daten nicht finden');

const ext = attachmentData.filename.split('.').pop() || 'pdf';
const uploadFilename = attachmentData.newName ? attachmentData.newName + '.' + ext : attachmentData.filename;
const sharePointPath = '/sites/<SITE>/DMS/Mail Anhänge/' + attachmentData.category + '/' + uploadFilename;

return { json: { ...attachmentData, uploadFilename, sharePointPath }, binary: binaryData };

const uploadResult = $input.first();
const prepData = $('Upload vorbereiten').first().json;
const serverUrl = uploadResult.json.d?.ServerRelativeUrl || prepData.sharePointPath;

const staticData = $getWorkflowStaticData('global');
if (!staticData.results) staticData.results = [];
if (!staticData.mailInfo) staticData.mailInfo = { mailId: prepData.mailId, mailSubject: prepData.mailSubject, mailFrom: prepData.mailFrom, mailDate: prepData.mailDate, totalAttachments: prepData.totalAttachments };

staticData.results.push({ filename: prepData.filename, uploadFilename: prepData.uploadFilename, size: prepData.fileSizeFormatted, category: prepData.category, sharePointPath: serverUrl, ocrStatus: prepData.ocrStatus, kiStatus: prepData.kiStatus, uploadStatus: '✓ Erfolgreich hochgeladen als: ' + prepData.uploadFilename, status: 'success', error: prepData.error || null });
return [{ json: { saved: true, count: staticData.results.length } }];

let prepData = {};
try { prepData = $('Upload vorbereiten').first().json; } catch(e) {}
let errorMsg = 'Upload fehlgeschlagen';
try { const e = $input.first().json.error; if (e) errorMsg = typeof e === 'string' ? e : e.message || JSON.stringify(e); } catch(e) {}

const staticData = $getWorkflowStaticData('global');
if (!staticData.results) staticData.results = [];
if (!staticData.mailInfo) staticData.mailInfo = { mailId: prepData.mailId || 'unbekannt', mailSubject: prepData.mailSubject || 'unbekannt', mailFrom: prepData.mailFrom || 'unbekannt', mailDate: prepData.mailDate || 'unbekannt', totalAttachments: prepData.totalAttachments || 1 };
staticData.results.push({ filename: prepData.filename || 'unbekannt', uploadFilename: prepData.uploadFilename || 'unbekannt', size: prepData.fileSizeFormatted || 'unbekannt', category: prepData.category || 'Sonstiges', sharePointPath: 'NICHT HOCHGELADEN', ocrStatus: prepData.ocrStatus || 'unbekannt', kiStatus: prepData.kiStatus || 'unbekannt', uploadStatus: '✗ Upload fehlgeschlagen', status: 'error', error: errorMsg });
return [{ json: { saved: true, count: staticData.results.length } }];

const staticData = $getWorkflowStaticData('global');
const mailInfo = staticData.mailInfo || {};
const results = staticData.results || [];
let hasErrors = false, hasCriticalError = false;
for (const r of results) { if (r.status === 'error') { hasCriticalError = true; hasErrors = true; } else if (r.error) hasErrors = true; }

let formattedDate = mailInfo.mailDate;
try { if (mailInfo.mailDate && mailInfo.mailDate !== 'unbekannt') { const d = new Date(mailInfo.mailDate); formattedDate = d.toLocaleDateString('de-DE') + ' ' + d.toLocaleTimeString('de-DE'); } } catch(e) {}

staticData.results = [];
staticData.mailInfo = null;
return [{ json: { mailId: mailInfo.mailId, mailSubject: mailInfo.mailSubject, mailFrom: mailInfo.mailFrom, mailDate: formattedDate, totalAttachments: mailInfo.totalAttachments || results.length, processedAttachments: results.length, hasErrors, hasCriticalError, results } }];

const data = $input.first().json;
let summary = '═══════════════════════════════════════
📧 MAIL VERARBEITUNG ABGESCHLOSSEN
═══════════════════════════════════════

';
summary += '📬 MAIL
───────────────────────────────────────
';
summary += '   Betreff:  ' + data.mailSubject + '
';
summary += '   Von:      ' + data.mailFrom + '
';
summary += '   Datum:    ' + data.mailDate + '

';
summary += '📎 ATTACHMENTS
───────────────────────────────────────
';
summary += '   Verarbeitet: ' + data.processedAttachments + ' von ' + data.totalAttachments + '

';
summary += '📝 ERGEBNISSE
───────────────────────────────────────
';
for (let i = 0; i < data.results.length; i++) {
  const r = data.results[i];
  const icon = r.status === 'success' ? '✅' : '❌';
  summary += '
   ' + icon + ' ' + r.filename;
  if (r.uploadFilename && r.uploadFilename !== r.filename) summary += ' → ' + r.uploadFilename;
  summary += '
      OCR:       ' + r.ocrStatus + '
';
  summary += '      Kategorie: ' + r.kiStatus + '
';
  summary += '      Upload:    ' + r.uploadStatus + '
';
  summary += '      Pfad:      ' + r.sharePointPath + '
';
  if (r.error) summary += '      ⚠️ Fehler: ' + r.error + '
';
}
summary += '
📊 STATUS
───────────────────────────────────────
';
if (data.hasCriticalError) summary += '   ❌ FEHLGESCHLAGEN
';
else if (data.hasErrors) summary += '   ⚠️ MIT WARNUNGEN
';
else summary += '   ✅ ERFOLGREICH
';
summary += '═══════════════════════════════════════
';
console.log(summary);
return [{ json: { ...data, summary } }];
